import{_ as e,o as a,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Random Image API и публичная галерея","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/Other/random-image-api-and-public-gallery.md","filePath":"ru-RU/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"ru-RU/Other/random-image-api-and-public-gallery.md"};function i(n,t,s,c,l,p){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="random-image-api-и-публичная-галерея" tabindex="-1">Random Image API и публичная галерея <a class="header-anchor" href="#random-image-api-и-публичная-галерея" aria-label="Permalink to &quot;Random Image API и публичная галерея&quot;">​</a></h1><p>Обе функции настраиваются здесь:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API возвращает один случайный файл из выбранных директорий. Это полезно для фонов сайта, ротации аватаров или случайных изображений на внешних страницах.</p><p>После включения используйте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="настроики-random-image-api" tabindex="-1">Настройки Random Image API <a class="header-anchor" href="#настроики-random-image-api" aria-label="Permalink to &quot;Настройки Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Назначение</th></tr></thead><tbody><tr><td>Enable</td><td>Включает или выключает endpoint <code>/random</code>. Когда выключено, доступ запрещен.</td></tr><tr><td>Directories</td><td>Ограничивает директории, которые может использовать random API. Директории вне этого списка API использовать не может.</td></tr><tr><td>Call demo</td><td>Генерирует random API links, которые можно сразу скопировать.</td></tr></tbody></table><p>Можно выбрать несколько директорий. Например, если разрешены только <code>/landscape/</code> и <code>/portrait/</code>, random API может выбирать файлы только из этих директорий и их поддиректорий.</p><h2 id="параметры-random-image-api" tabindex="-1">Параметры Random Image API <a class="header-anchor" href="#параметры-random-image-api" aria-label="Permalink to &quot;Параметры Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Параметр</th><th>Пример</th><th>Назначение</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Указывает random directory.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Указывает media type. Используйте <code>image</code>, <code>video</code>, <code>audio</code> или комбинации через запятую.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Фильтрует ориентацию изображения. Используйте <code>portrait</code>, <code>landscape</code> или <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Формат ответа. Пусто — redirect, <code>url</code> возвращает plain text URL, <code>json</code> возвращает JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Вместе с <code>type=url</code> возвращает полный URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Фильтрует по age rating.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Возвращает только файлы с этими tags.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Исключает файлы с этими tags.</td></tr></tbody></table><h2 id="форматы-ответа" tabindex="-1">Форматы ответа <a class="header-anchor" href="#форматы-ответа" aria-label="Permalink to &quot;Форматы ответа&quot;">​</a></h2><p>Без <code>type</code> API напрямую redirect-ит на URL случайного файла.</p><p>С <code>type=url</code> он возвращает текстовый URL.</p><p>С <code>type=json</code> возвращает информацию о файле, включая file URL, file ID, file name, file type, tags, rating и связанные metadata.</p><h2 id="правила-доступа" tabindex="-1">Правила доступа <a class="header-anchor" href="#правила-доступа" aria-label="Permalink to &quot;Правила доступа&quot;">​</a></h2><p>Random Image API соблюдает public access rules:</p><table tabindex="0"><thead><tr><th>Правило</th><th>Эффект</th></tr></thead><tbody><tr><td>Directory restriction</td><td>Выбираться могут только файлы в разрешенных директориях.</td></tr><tr><td>Blocklist</td><td>Blocklisted files исключаются из random pool.</td></tr><tr><td>Allowlist mode</td><td>Когда включено, возвращаются только файлы, разрешенные для public access.</td></tr><tr><td>Age rating</td><td>R12, R16, R18 и похожий контент фильтруется текущим access mode.</td></tr></tbody></table><p>Если после фильтрации нет подходящего файла, API возвращает отсутствие совпадений.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API кеширует candidate pools директорий для более быстрой работы.</p><p>После изменения файлов ImgBed обновляет cache version директории, и следующие запросы перестраивают candidate pool. Пустые директории кешируются ненадолго, чтобы избежать повторных запросов.</p><h2 id="публичная-галерея" tabindex="-1">Публичная галерея <a class="header-anchor" href="#публичная-галерея" aria-label="Permalink to &quot;Публичная галерея&quot;">​</a></h2><p>Публичная галерея дает read-only страницу просмотра для директорий, которые вы разрешите видеть посетителям.</p><p>После включения посетители могут открыть:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="настроики-публичнои-галереи" tabindex="-1">Настройки публичной галереи <a class="header-anchor" href="#настроики-публичнои-галереи" aria-label="Permalink to &quot;Настройки публичной галереи&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опция</th><th>Назначение</th></tr></thead><tbody><tr><td>Enable</td><td>Включает или выключает публичную галерею. Когда выключено, посетители не могут ее просматривать.</td></tr><tr><td>Image loading mode</td><td>Определяет, используют ли preview оригиналы или thumbnails.</td></tr><tr><td>Open directories</td><td>Определяет, какие директории доступны посетителям.</td></tr></tbody></table><h2 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Назначение</th></tr></thead><tbody><tr><td>Original</td><td>Страница посетителя загружает оригинальные файлы напрямую.</td></tr><tr><td>Thumbnail</td><td>Страница посетителя предпочитает thumbnails для более быстрой загрузки.</td></tr></tbody></table><h2 id="open-directories" tabindex="-1">Open Directories <a class="header-anchor" href="#open-directories" aria-label="Permalink to &quot;Open Directories&quot;">​</a></h2><p>Open directories определяют, что видят посетители.</p><p>Например:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Тогда посетители могут открыть:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Поддиректории тоже можно открывать, например <code>/2026/lucky/</code>. Посетители блокируются в директориях, которые не открыты.</p><h2 id="возможности-публичнои-галереи" tabindex="-1">Возможности публичной галереи <a class="header-anchor" href="#возможности-публичнои-галереи" aria-label="Permalink to &quot;Возможности публичной галереи&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Возможность</th><th>Описание</th></tr></thead><tbody><tr><td>Browse directories</td><td>Просмотр файлов и поддиректорий в открытых директориях.</td></tr><tr><td>Search</td><td>Поиск по file name, file ID или tags.</td></tr><tr><td>Type filter</td><td>Фильтр images, videos, audio или других файлов.</td></tr><tr><td>Tag filter</td><td>Включение или исключение выбранных tags.</td></tr><tr><td>Orientation filter</td><td>Фильтр landscape или portrait images.</td></tr><tr><td>Time filter</td><td>Фильтр по диапазону времени загрузки.</td></tr><tr><td>Extension filter</td><td>Фильтр по file extension.</td></tr><tr><td>Copy link</td><td>Копирование file access links.</td></tr><tr><td>Media preview</td><td>Просмотр или воспроизведение images, videos и audio на странице посетителя.</td></tr></tbody></table><h2 id="правила-доступа-публичнои-галереи" tabindex="-1">Правила доступа публичной галереи <a class="header-anchor" href="#правила-доступа-публичнои-галереи" aria-label="Permalink to &quot;Правила доступа публичной галереи&quot;">​</a></h2><p>Публичная галерея также соблюдает public access rules:</p><table tabindex="0"><thead><tr><th>Правило</th><th>Эффект</th></tr></thead><tbody><tr><td>Open directories</td><td>Показываются только разрешенные директории.</td></tr><tr><td>Access mode</td><td>Контент фильтруется текущим age-rating access mode.</td></tr><tr><td>Allowlist mode</td><td>Когда включено, показываются только файлы, разрешенные для public access.</td></tr><tr><td>Blocklist</td><td>Blocklisted files скрыты.</td></tr></tbody></table>`,43)])])}const b=e(r,[["render",i]]);export{m as __pageData,b as default};
